parameters.query:
DO $$
DECLARE
  target_phone text := '{{ $('SET telefone').last().json.telefone.split('@')[0] }}';
BEGIN
  -- Step 1: Delete from user_session
  DELETE FROM public.user_session
  WHERE telefone = target_phone;

  -- Step 2: Set deletado = true in sessao_agendamento 
  DELETE FROM public.sessao_agendamento 
  WHERE telefone = target_phone;

  -- Step 3: Delete from cliente
  DELETE FROM public.cliente
  WHERE telefone = target_phone;

END $$;

parameters.messageData:
={{ JSON.stringify({
      timestamp: new Date().toISOString(),
      message: $('SET mensagem').last().json.mensagem 
    }) }}

